static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard2dSquareInputAsymmetricKernelCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    uint32_t batch = x_shape->GetDim(0);
    uint32_t inC  = x_shape->GetDim(1);
    uint32_t inH  = x_shape->GetDim(2);
    uint32_t inW  = x_shape->GetDim(3);
    uint32_t outC = w_shape->GetDim(0);
    uint32_t kH   = w_shape->GetDim(2);
    uint32_t kW   = w_shape->GetDim(3);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *stride = attrs->GetAttrPointer<int64_t>(0);
    const int64_t *padding = attrs->GetAttrPointer<int64_t>(1);
    const int64_t *dilation = attrs->GetAttrPointer<int64_t>(2);
    int64_t groups = attrs->GetAttrValue<int64_t>(3);

    uint32_t strideH = static_cast<uint32_t>(stride[0]);
    uint32_t strideW = static_cast<uint32_t>(stride[1]);
    uint32_t padH = static_cast<uint32_t>(padding[0]);
    uint32_t padW = static_cast<uint32_t>(padding[1]);
    uint32_t dilationH = static_cast<uint32_t>(dilation[0]);
    uint32_t dilationW = static_cast<uint32_t>(dilation[1]);

    uint32_t outH = (inH + 2 * padH - dilationH * (kH - 1) - 1) / strideH + 1;
    uint32_t outW = (inW + 2 * padW - dilationW * (kW - 1) - 1) / strideW + 1;

    uint32_t totalElements = batch * outC * outH * outW;
    // Simple tiling: use output channel blocks
    uint32_t maxTileOC = UB_BUDGET_BYTES / (inC * kH * kW * sizeof(float) * 3); // rough
    if (maxTileOC > outC) maxTileOC = outC;
    if (maxTileOC < 1) maxTileOC = 1;

    uint32_t blockDim = 8;
    if (outC > 16) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalElements);
    tiling.set_tileLength(maxTileOC);
    tiling.set_blockDim(blockDim);

    tiling.set_batch(batch);
    tiling.set_inChannels(inC);
    tiling.set_outChannels(outC);
    tiling.set_inH(inH);
    tiling.set_inW(inW);
    tiling.set_kernelH(kH);
    tiling.set_kernelW(kW);
